import { IMessageComposer } from '@nitrots/nitro-renderer';

export class TradeRemoveItemComposer implements IMessageComposer<any[]>
{
private _data: any[];

constructor(sessionId: number, slotIndex: number)
{
// Must match TradeRemoveItemEvent.java order
this._data = [
sessionId,
slotIndex
];

console.log('Packet TradeRemoveItemComposer sent');
}

public getMessageArray(): any[]
{
return this._data;
}

public dispose(): void
{
return;
}
}
